self.addEventListener("push",t=>{if(!t.data)return;let i=t.data.json();t.waitUntil(self.registration.showNotification(i.title,{body:i.body,icon:i.icon||"/favicon.ico",badge:"/favicon.ico",tag:i.tag||"momo-notification",data:{url:i.url||"/dashboard"}}))}),self.addEventListener("notificationclick",t=>{t.notification.close(),t.waitUntil(clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{let o=t.notification.data?.url||"/dashboard";for(let t of i)if(t.url===o&&"focus"in t)return t.focus();return clients.openWindow(o)}))});